def validate_script(script_source):
    """Validate script content against security rules."""
    if not isinstance(script_source, str):
        return False, "Script source must be a string"

    if len(script_source) > MAX_SCRIPT_LENGTH:
        return False, f"Script exceeds maximum length of {MAX_SCRIPT_LENGTH} characters"

    if not script_source.strip():
        return False, "Script source cannot be empty"

    # Check for blocked patterns (case-insensitive for some)
    script_lower = script_source.lower()
    for pattern in BLOCKED_PATTERNS:
        if pattern.lower() in script_lower:
            return False, f"Script contains blocked pattern: '{pattern}'"

    return True, "Valid"


def validate_params(params):
    """Validate script parameters."""
    if params is None:
        return True, "Valid"

    if not isinstance(params, dict):
        return False, "Params must be a dictionary"

    if len(params) > MAX_PARAMS_COUNT:
        return False, f"Too many parameters (max {MAX_PARAMS_COUNT})"

    for key, value in params.items():
        if not isinstance(key, str):
            return False, "Parameter keys must be strings"
        if not isinstance(key, str) or not key.isidentifier():
            return False, f"Invalid parameter name: {key}"
        # Only allow primitive types in params
        if not isinstance(value, (int, float, str, bool)):
            return False, f"Parameter '{key}' has unsupported type: {type(value).__name__}"

    return True, "Valid"


